// // This module implements an 8-bit binary up-counter with enable and active-low reset.
module binary_down_counter (
    input clk,
    input rst,
    input en,
    output reg [7:0] count
);

always @(posedge clk or posedge rst) begin
    if (rst)
        count <= 8'b11111111;
    else if (en)
        count <= count - 1;
end

endmodule
